import { forwardRef, type HTMLAttributes, type ReactNode } from "react";
import { Slot } from "@radix-ui/react-slot";
import { clsx } from "clsx";
import { type StackLayoutProps, stackStyles } from "./Stack.sprinkles";
import { stack } from "./Stack.css";

interface StackCustomProps extends StackLayoutProps {
  /**
   * When true, renders the child element instead of a div,
   * merging Stack's props and behavior onto the child.
   */
  asChild?: boolean;
  children?: ReactNode;
}

export interface StackProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof StackCustomProps>,
    StackCustomProps {}

export const Stack = forwardRef<HTMLDivElement, StackProps>(
  (
    {
      direction,
      gap,
      rowGap,
      columnGap,
      alignItems,
      justifyContent,
      alignContent,
      wrap,
      asChild,
      className,
      children,
      ...props
    },
    ref
  ) => {
    const Component = asChild ? Slot : "div";

    return (
      <Component
        ref={ref}
        className={clsx(
          stack,
          stackStyles({
            direction,
            gap,
            rowGap,
            columnGap,
            alignItems,
            justifyContent,
            alignContent,
            wrap,
          }),
          className
        )}
        {...props}
      >
        {children}
      </Component>
    );
  }
);

Stack.displayName = "Stack";
