/**
 * Stack sprinkles - types, config, and style generator for Stack component.
 */

import { stackSprinkles, type StackSprinkles } from "./Stack.sprinkles.css";
import type { SpacingKey, Responsive } from "../_internal/sprinkles/types";
import { assignProp } from "../_internal/sprinkles/utils";

// ═══════════════════════════════════════════════════════════════════════════════
// TYPES & CONFIG
// ═══════════════════════════════════════════════════════════════════════════════

/** Flex direction values (CSS) */
export const FlexDirections = [
  "row",
  "column",
  "row-reverse",
  "column-reverse",
] as const;
export type FlexDirection = (typeof FlexDirections)[number];

/** Flex wrap values */
export const FlexWraps = ["nowrap", "wrap", "wrap-reverse"] as const;
export type FlexWrap = (typeof FlexWraps)[number];

/** Align items values */
export const AlignItemsValues = [
  "flex-start",
  "flex-end",
  "center",
  "stretch",
  "baseline",
] as const;
export type AlignItems = (typeof AlignItemsValues)[number];

/** Justify content values */
export const JustifyContentValues = [
  "flex-start",
  "flex-end",
  "center",
  "space-between",
  "space-around",
  "space-evenly",
] as const;
export type JustifyContent = (typeof JustifyContentValues)[number];

/** Align content values */
export const AlignContentValues = [
  "flex-start",
  "flex-end",
  "center",
  "stretch",
  "space-between",
  "space-around",
] as const;
export type AlignContent = (typeof AlignContentValues)[number];

/**
 * Stack layout props - CSS-aligned prop names for flexbox layout.
 *
 * All props support responsive values via an object with breakpoint keys:
 * - `base`: All screen sizes (mobile-first default)
 * - `sm`: 640px and up
 * - `md`: 768px and up
 * - `lg`: 1024px and up
 * - `xl`: 1280px and up
 * - `2xl`: 1536px and up
 *
 * @example
 * // Responsive layout: column on mobile, row on md+
 * <Stack direction={{ base: "column", md: "row" }} gap={{ base: "8", md: "16" }} />
 */
export interface StackLayoutProps {
  /**
   * Flex direction.
   * @example
   * // Static value
   * <Stack direction="column" />
   * @example
   * // Responsive: column on mobile, row on md+
   * <Stack direction={{ base: "column", md: "row" }} />
   */
  direction?: Responsive<FlexDirection> | undefined;
  /**
   * Gap between all items (spacing token). Maps to CSS `gap`.
   * @example
   * // Static value
   * <Stack gap="16" />
   * @example
   * // Responsive: 8px on mobile, 16px on md+, 24px on lg+
   * <Stack gap={{ base: "8", md: "16", lg: "24" }} />
   */
  gap?: Responsive<SpacingKey> | undefined;
  /**
   * Gap between rows (vertical spacing). Maps to CSS `row-gap`.
   * @example
   * // Static value
   * <Stack wrap="wrap" rowGap="16" columnGap="8" />
   * @example
   * // Responsive: 8px on mobile, 16px on md+
   * <Stack wrap="wrap" rowGap={{ base: "8", md: "16" }} />
   */
  rowGap?: Responsive<SpacingKey> | undefined;
  /**
   * Gap between columns (horizontal spacing). Maps to CSS `column-gap`.
   * @example
   * // Static value
   * <Stack wrap="wrap" rowGap="16" columnGap="8" />
   * @example
   * // Responsive: 4px on mobile, 8px on md+
   * <Stack wrap="wrap" columnGap={{ base: "4", md: "8" }} />
   */
  columnGap?: Responsive<SpacingKey> | undefined;
  /**
   * Align items along the cross-axis.
   * @example
   * // Static value
   * <Stack alignItems="center" />
   * @example
   * // Responsive: stretch on mobile, center on md+
   * <Stack alignItems={{ base: "stretch", md: "center" }} />
   */
  alignItems?: Responsive<AlignItems> | undefined;
  /**
   * Distribute space along the main-axis.
   * @example
   * // Static value
   * <Stack justifyContent="space-between" />
   * @example
   * // Responsive: flex-start on mobile, space-between on md+
   * <Stack justifyContent={{ base: "flex-start", md: "space-between" }} />
   */
  justifyContent?: Responsive<JustifyContent> | undefined;
  /**
   * Align wrapped lines along the cross-axis (only applies when `wrap` is set).
   * @example
   * // Static value
   * <Stack wrap="wrap" alignContent="space-between" />
   * @example
   * // Responsive: flex-start on mobile, space-between on md+
   * <Stack wrap="wrap" alignContent={{ base: "flex-start", md: "space-between" }} />
   */
  alignContent?: Responsive<AlignContent> | undefined;
  /**
   * Whether items wrap to new lines.
   * @example
   * // Static value
   * <Stack wrap="wrap" />
   * @example
   * // Responsive: nowrap on mobile, wrap on md+
   * <Stack wrap={{ base: "nowrap", md: "wrap" }} />
   */
  wrap?: Responsive<FlexWrap> | undefined;
}

// ═══════════════════════════════════════════════════════════════════════════════
// STYLE GENERATOR
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * Generate className for Stack props.
 */
export function stackStyles(props: StackLayoutProps): string {
  const sprinkleProps: StackSprinkles = {};

  assignProp(sprinkleProps, "flexDirection", props.direction);
  assignProp(sprinkleProps, "gap", props.gap);
  assignProp(sprinkleProps, "rowGap", props.rowGap);
  assignProp(sprinkleProps, "columnGap", props.columnGap);
  assignProp(sprinkleProps, "alignItems", props.alignItems);
  assignProp(sprinkleProps, "justifyContent", props.justifyContent);
  assignProp(sprinkleProps, "alignContent", props.alignContent);
  assignProp(sprinkleProps, "flexWrap", props.wrap);

  return stackSprinkles(sprinkleProps);
}
